module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                    clk,
    input  logic                    rst_n,
    input  logic                    enable,
    input  logic                    clear,
    input  logic [STEP_WIDTH-1:0]   step,
    output logic [COUNT_WIDTH-1:0]  count,
    output logic                    wrapped,
    output logic                    valid
);

    // SSOT memory.instances ownership:
    // - count_state_ff   : depth=1, width=COUNT_WIDTH, latency=0 register storage
    // - wrapped_state_ff : depth=1, width=1,           latency=0 register storage
    // - valid_state_ff   : depth=1, width=1,           latency=0 register storage
    logic [COUNT_WIDTH-1:0] count_state_ff;
    logic                   wrapped_state_ff;
    logic                   valid_state_ff;

    // Zero-extend step to counter width, then form carry-out sum for overflow detection.
    logic [COUNT_WIDTH-1:0] step_ext;
    logic [COUNT_WIDTH:0]   sum_ext;

    assign step_ext = {{(COUNT_WIDTH-STEP_WIDTH){1'b0}}, step};
    assign sum_ext  = {1'b0, count_state_ff} + {1'b0, step_ext};

    // Architectural outputs are directly observable from state FFs.
    assign count   = count_state_ff;
    assign wrapped = wrapped_state_ff;
    assign valid   = valid_state_ff;

    // Priority chain required by SSOT: reset -> clear -> enable update -> idle hold/deassert pulses.
    // Latency-1 contract: for enable=1, commit count/wrapped/valid at the accepting edge.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count_state_ff   <= {COUNT_WIDTH{1'b0}};
            wrapped_state_ff <= 1'b0;
            valid_state_ff   <= 1'b0;
        end else if (clear) begin
            count_state_ff   <= {COUNT_WIDTH{1'b0}};
            wrapped_state_ff <= 1'b0;
            valid_state_ff   <= 1'b0;
        end else if (enable) begin
            count_state_ff   <= sum_ext[COUNT_WIDTH-1:0];
            wrapped_state_ff <= sum_ext[COUNT_WIDTH];
            valid_state_ff   <= 1'b1;
        end else begin
            count_state_ff   <= count_state_ff;
            wrapped_state_ff <= 1'b0;
            valid_state_ff   <= 1'b0;
        end
    end

endmodule

